import React, { useEffect, useState } from "react";
import ReactMapGL, { Marker } from "react-map-gl";

const MapComponent = () => {
  const [viewport, setViewport] = useState({
    latitude: 40.7128, // NYC center
    longitude: -74.0060,
    zoom: 10,
    width: "100vw",
    height: "100vh",
  });

  const [buses, setBuses] = useState([]);

  // Fetch bus data every 5 seconds
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();
        setBuses(data);
      } catch (error) {
        console.error("Error fetching bus data:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <ReactMapGL
      {...viewport}
      mapboxApiAccessToken="YOUR_MAPBOX_TOKEN"
      onViewportChange={(nextViewport) => setViewport(nextViewport)}
    >
      {buses.map((bus) => (
        <Marker key={bus.id} latitude={bus.lat} longitude={bus.lon}>
          <div
            style={{
              width: "15px",
              height: "15px",
              borderRadius: "50%",
              backgroundColor: bus.status === "ghost" ? "red" : "green",
              border: "2px solid white",
            }}
            title={`Bus ID: ${bus.id} | Status: ${bus.status}`}
          />
        </Marker>
      ))}
    </ReactMapGL>
  );
};

export default MapComponent;
